#!/usr/bin/env python
# encoding: utf-8

'''
Класс для создания html-страницы с использованием таблицы стилей CSS.
Для создания разметки используется шаблоны django.

В отдельный файл sitesty.css вынесены все элементы форматирования.
'''

from django.conf import settings
from os import getcwd, path

TEMPLATES = [
    {
        'BACKEND': 'django.template.backends.django.DjangoTemplates',
        'DIRS': ['/path/to/template'],
    }
]
settings.configure(TEMPLATE_DIRS=(getcwd,), DEBUG=False,TEMPLATE_DEBUG=False,TEMPLATES=TEMPLATES)
from django import template
import django
django.setup()

class HtmlPageGenerator():
 def __init__(self, observatory):
  self.pagecontent = u""

  self.raw_template_begin='''
<HTML>
<HEAD>
<link REL="stylesheet" type="text/css" href="sitesty.css">
<META HTTP-EQUIV="CONTENT-TYPE" CONTENT="text/html; charset=utf-8">
<TITLE> {{htmltitle}}</TITLE>
<script language="JavaScript" src="transits.js" type="text/javascript"></script>
</HEAD>
<BODY>
'''
  
  self.raw_template_middle='''
<!-- new date -->
<H1 CLASS="DATETIME" id="{{ currentDate }}">{{ currentDate }}</H1>
<P>
<IMG SRC='{{ currentDate }}.jpeg'></IMG>
<BR/>
</P>
<TABLE CLASS="OBJECT">
<CAPTION>
Transits of objects
</CAPTION>
   <TR>
   <TH>Name</TH> 
   <TH>Transit time (UTC)</TH>
   <TH>Transit time ({{ observatory.UtcOffset }})</TH>
   <TH>RA (2000.)</TH> 
   <TH>DEC (2000.)</TH>
   <TH>T0 (JD)</TH>
   <TH>Period (days)</TH>
   <TH>Duraction (hours)</TH>
   <TH>Depth (mag)</TH>
   <TH>Mag</TH>
   <TH>(Az,Z)</TH>
   </TR>
{% for object in object_list %}
 {% for transitInfo in object.transitsList %}
  {% if transitInfo.isNight and transitInfo.middle_z < 90 %}
    <TR>
    <TD> 
     <A HREF="./png/{{ object.name }}.png">
     {{ object.name }}
     </A>
    </TD>
    <TD> {{ transitInfo.middle }} </TD>
    <TD> {{ transitInfo.middle_utc }} </TD>
    <TD> {{ object.RA }} </TD>
    <TD> {{ object.DEC }} </TD>
    <TD> {{ object.transittime }} </TD>
    <TD> {{ object.period }} </TD>
    <TD> {{ object.duraction }} </TD>
    <TD> {{ object.trans_depht }} </TD>
    <TD> {{ object.mag }} </TD>
    <TD CLASS="{{ transitInfo.middle_color }}"> ({{ transitInfo.middle_az }},{{ transitInfo.middle_z }})  </TD>
    </TR>
  {% endif %}
 {% endfor %}
{% endfor %}
</TABLE>

<TABLE CLASS="TWILIGHTS">
<CAPTION>
Twilights
</CAPTION>
<TR>
<TH>Nautical</TH>
<TH>Astronomical</TH>
<TH>Midnight</TH>
<TH>Astronomical</TH>
<TH>Nautical</TH>
</TR>
<TR>
<TD> {{ SolarTwilight.Nautical0 }} </TD>
<TD> {{ SolarTwilight.Astronomical0 }} </TD>
<TD> {{ SolarTwilight.Midnight}} </TD>
<TD> {{SolarTwilight.Astronomical1}} </TD>
<TD> {{ SolarTwilight.Nautical1 }} </TD>
</TR>
</TABLE>
'''

  self.raw_template_end='''
</BODY>
</HTML>
'''

  self.begin(observatory)

 def begin(self, observatory):
  t = template.Template(self.raw_template_begin)
  c = template.Context({
  "htmltitle": observatory["Title"],
  })
  self.pagecontent += t.render(c)

 def middle(self, dateOfInterest, listObjectOfInterest, solarTwilight, observatory ):
  t = template.Template(self.raw_template_middle)
  c = template.Context({
  "currentDate": dateOfInterest,
  "SolarTwilight": solarTwilight,
  "object_list": listObjectOfInterest,
  "observatory": observatory,
  })
  
  self.pagecontent += t.render(c)

 def end(self):
  t = template.Template(self.raw_template_end)
  c = template.Context()
  self.pagecontent += t.render(c)


 def writeto(self, FileName):
  self.end()
  open(FileName,mode="w").write(self.pagecontent)
